mainmatter.pre:
\title{creation of (co)limits}
\date{2023-02-11}
\taxon{definition}
\author{jonmsterling}

\def\CCat{#{\mathcal{C}}}
\def\DCat{#{\mathcal{D}}}
\def\ICat{#{\mathcal{I}}}
\def\Mor[arg1][arg2][arg3]{#{{\arg2}\xrightarrow{\arg1}{\arg3}}}

\p{Let \Mor{U}{\CCat}{\DCat} be a functor and let \ICat be a category. The functor #{U} is said to \em{create (co)limits of #{\ICat}-figures} when for any diagram \Mor{C_\bullet}{\ICat}{\CCat} such that #{\ICat\xrightarrow{C_\bullet}\CCat\xrightarrow{F}\DCat} has a (co)limit, then #{C_\bullet} has a (co)limit that is both preserved and reflected by #{F}.}

li.tex:
\begin{aligned}         TTc_ \bullet ; { \left \{ T \beta \right \} } ; { \left \{ \beta \right \} }         & =
     T { \left ( Tc_ \bullet ; { \left \{ \beta \right \} } \right )} ; { \left \{ \beta \right \} }          \\         & =
     T { \left ( \alpha _{X_ \bullet };c_ \bullet \right )} ; { \left \{ \beta \right \} }          \\         & =
     T \alpha _{X_ \bullet };Tc_ \bullet ; { \left \{ \beta \right \} }          \\         & =
     T \alpha _{X_ \bullet }; \alpha _{X_ \bullet };c_ \bullet          \\         & =
      \mu _{UX_ \bullet };
      \alpha _{X_ \bullet };
     c_ \bullet          \\         & =
      \mu _{UX_ \bullet };Tc_ \bullet ; { \left \{ \beta \right \} }        \end{aligned}

\begin{aligned}         TTc_ \bullet ; { \left \{ T \beta \right \} } ; { \left \{ \beta \right \} }         & =
     T { \left ( Tc_ \bullet ; { \left \{ \beta \right \} } \right )} ; { \left \{ \beta \right \} }          \\         & =
     T { \left ( \alpha _{X_ \bullet };c_ \bullet \right )} ; { \left \{ \beta \right \} }          \\         & =
     T \alpha _{X_ \bullet };Tc_ \bullet ; { \left \{ \beta \right \} }          \\         & =
     T \alpha _{X_ \bullet }; \alpha _{X_ \bullet };c_ \bullet          \\         & =
      \mu _{UX_ \bullet };
      \alpha _{X_ \bullet };
     c_ \bullet          \\         & =
      \mu _{UX_ \bullet };Tc_ \bullet ; { \left \{ \beta \right \} }        \end{aligned}
